sql.transaction:
CREATE DATABASE hr_agency
    ENCODING 'UTF8'
    TEMPLATE template0;

SELECT '== КОМПАНИИ ==' AS info;
SELECT id, name, description FROM company ORDER BY id;

SELECT '== ВАКАНСИИ ==' AS info;
SELECT v.id, c.name AS company, v.position, v.salary,
       v.required_education, v.requirements, v.status
FROM vacancy v
JOIN company c ON c.id = v.company_id
ORDER BY v.company_id, v.id;

SELECT '== ЛЮДИ ==' AS info;
SELECT id, full_name, education, status, desired_position, desired_salary
FROM person
ORDER BY id;

SELECT '== ИСТОРИЯ РАБОТЫ ==' AS info;
SELECT we.id, p.full_name, c.name AS company, we.position, we.salary,
       we.start_date, we.end_date
FROM work_experience we
JOIN person p ON p.id = we.person_id
JOIN company c ON c.id = we.company_id
ORDER BY p.id, we.start_date;
